package com.ecoPedal.backend.entity;import com.ecoPedal.backend.entity.enums.MethodePaiement;import com.ecoPedal.backend.entity.enums.StatutPaiement;import jakarta.persistence.*;import lombok.*;import java.time.LocalDateTime;@Getter@Setter@NoArgsConstructor@AllArgsConstructor@Entity@Table(name = "paiement")public class Paiement {    @Id    @GeneratedValue(strategy = GenerationType.IDENTITY)    private Long id;    @Column(nullable = false)    private Double montant;    @Enumerated(EnumType.STRING)    private MethodePaiement methode ;    @Enumerated(EnumType.STRING)    private StatutPaiement statut ;    private LocalDateTime datePaiement;    @ManyToOne    @JoinColumn(name = "id_utilisateur", nullable = false)    private Utilisateur utilisateur;    @ManyToOne    @JoinColumn(name = "id_reservation", nullable = false)    private Reservation reservation;    @OneToOne    @JoinColumn(name = "id_location", nullable = false)    private Location location;}